mapper.select:
/* CouponMapper.getAdminCouponList: 관리자 쿠폰 목록 조회 */ SELECT CB.CPN_NO , CB.CPN_NM , CCS.CD_NM AS CPN_STAT_NM , CCG.CD_NM AS CPN_GB_NM , CCT.CD_NM AS CPN_TARGET_NM , CASE WHEN CB.CPN_DOWN_START_DT IS NULL OR CB.CPN_DOWN_START_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.CPN_DOWN_START_DT, '%Y-%m-%d %H') END AS CPN_DOWN_START_DT , CASE WHEN CB.CPN_DOWN_END_DT IS NULL OR CB.CPN_DOWN_END_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.CPN_DOWN_END_DT, '%Y-%m-%d %H') END AS CPN_DOWN_END_DT , CB.CPN_DOWN_ABLE_YN , CASE WHEN CB.STAT_STOP_DT IS NULL OR CB.STAT_STOP_DT = '0000-00-00 00:00:00' THEN '' ELSE DATE_FORMAT(CB.STAT_STOP_DT, '%Y-%m-%d %H') END AS STAT_STOP_DT FROM COUPON_BASE CB LEFT JOIN COMMON_CODE CCS ON CCS.GRP_CD = 'CPN_STAT' AND CCS.CD = CB.CPN_STAT_CD LEFT JOIN COMMON_CODE CCG ON CCG.GRP_CD = 'CPN_GB' AND CCG.CD = CB.CPN_GB_CD LEFT JOIN COMMON_CODE CCT ON CCT.GRP_CD = 'CPN_TARGET' AND CCT.CD = CB.CPN_TARGET_CD WHERE IFNULL(CB.DEL_YN, 'N') = 'N'
AND CB.CPN_NO = #{searchValue}
AND CB.CPN_NM LIKE CONCAT(#{searchValue}, '%')
AND CB.REG_DT >= #{searchStartDt}
AND CB.REG_DT <= #{searchEndDt}
AND IFNULL(NULLIF(CB.CPN_DOWN_END_DT, '0000-00-00 00:00:00'), '9999-12-31 23:59:59') >= #{searchStartDt}
AND IFNULL(NULLIF(CB.CPN_DOWN_START_DT, '0000-00-00 00:00:00'), '1000-01-01 00:00:00') <= #{searchEndDt}
AND CB.CPN_STAT_CD = #{cpnStatCd}
AND CB.CPN_GB_CD = #{cpnGbCd}
AND CB.CPN_TARGET_CD = #{cpnTargetCd}
AND CB.CPN_DOWN_ABLE_YN = #{cpnDownAbleYn}
ORDER BY CB.CPN_NO DESC LIMIT #{pageSize} OFFSET #{offset}

/* CouponMapper.getAdminCouponCount: 관리자 쿠폰 목록 건수 조회 */
SELECT COUNT(1)
  FROM COUPON_BASE CB
 WHERE IFNULL(CB.DEL_YN, 'N') = 'N'

  AND CB.CPN_NO = #{searchValue}


  AND CB.CPN_NM LIKE CONCAT(#{searchValue}, '%')


  AND CB.REG_DT >= #{searchStartDt}


  AND CB.REG_DT <= #{searchEndDt}


  AND IFNULL(NULLIF(CB.CPN_DOWN_END_DT, '0000-00-00 00:00:00'), '9999-12-31 23:59:59') >= #{searchStartDt}


  AND IFNULL(NULLIF(CB.CPN_DOWN_START_DT, '0000-00-00 00:00:00'), '1000-01-01 00:00:00') <= #{searchEndDt}


  AND CB.CPN_STAT_CD = #{cpnStatCd}


  AND CB.CPN_GB_CD = #{cpnGbCd}


  AND CB.CPN_TARGET_CD = #{cpnTargetCd}


  AND CB.CPN_DOWN_ABLE_YN = #{cpnDownAbleYn}

mapper.insert:
/* CouponMapper.insertCouponBase: 관리자 쿠폰 등록 */
INSERT INTO COUPON_BASE (
       CPN_NM
     , CPN_STAT_CD
     , CPN_GB_CD
     , CPN_TARGET_CD
     , CPN_DOWN_START_DT
     , CPN_DOWN_END_DT
     , CPN_USE_DT_GB
     , CPN_USABLE_DT
     , CPN_USE_START_DT
     , CPN_USE_END_DT
     , DEL_YN
     , CPN_DOWN_ABLE_YN
     , STAT_STOP_DT
     , REG_NO
     , UDT_NO
) VALUES (
       #{cpnNm}
     , #{cpnStatCd}
     , #{cpnGbCd}
     , #{cpnTargetCd}
     , COALESCE(NULLIF(#{cpnDownStartDt}, ''), NOW())
     , COALESCE(NULLIF(#{cpnDownEndDt}, ''), '0000-00-00 00:00:00')
     , #{cpnUseDtGb}
     , #{cpnUsableDt}
     , COALESCE(NULLIF(#{cpnUseStartDt}, ''), '0000-00-00 00:00:00')
     , COALESCE(NULLIF(#{cpnUseEndDt}, ''), '0000-00-00 00:00:00')
     , 'N'
     , COALESCE(NULLIF(#{cpnDownAbleYn}, ''), 'Y')
     , COALESCE(NULLIF(#{statStopDt}, ''), '0000-00-00 00:00:00')
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* CouponMapper.updateCouponBase: 관리자 쿠폰 수정 */
UPDATE COUPON_BASE
   SET CPN_NM = #{cpnNm}
     , CPN_STAT_CD = #{cpnStatCd}
     , CPN_GB_CD = #{cpnGbCd}
     , CPN_TARGET_CD = #{cpnTargetCd}
     , CPN_DOWN_START_DT = COALESCE(NULLIF(#{cpnDownStartDt}, ''), NOW())
     , CPN_DOWN_END_DT = COALESCE(NULLIF(#{cpnDownEndDt}, ''), '0000-00-00 00:00:00')
     , CPN_USE_DT_GB = #{cpnUseDtGb}
     , CPN_USABLE_DT = #{cpnUsableDt}
     , CPN_USE_START_DT = COALESCE(NULLIF(#{cpnUseStartDt}, ''), '0000-00-00 00:00:00')
     , CPN_USE_END_DT = COALESCE(NULLIF(#{cpnUseEndDt}, ''), '0000-00-00 00:00:00')
     , CPN_DOWN_ABLE_YN = COALESCE(NULLIF(#{cpnDownAbleYn}, ''), 'Y')
     , STAT_STOP_DT = COALESCE(NULLIF(#{statStopDt}, ''), '0000-00-00 00:00:00')
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CPN_NO = #{cpnNo}
   AND IFNULL(DEL_YN, 'N') = 'N'

mapper.select:
/* CouponMapper.countCouponByNo: 쿠폰 존재 여부 조회 */
SELECT COUNT(1)
  FROM COUPON_BASE
 WHERE CPN_NO = #{cpnNo}
   AND IFNULL(DEL_YN, 'N') = 'N'

mapper.delete:
/* CouponMapper.deleteCouponTargetByCpnNo: 관리자 쿠폰 대상 삭제 */
DELETE
  FROM COUPON_TARGET
 WHERE CPN_NO = #{cpnNo}

mapper.insert:
/* CouponMapper.insertCouponTargetBatch: 관리자 쿠폰 대상 배치 등록 */
INSERT INTO COUPON_TARGET (
       CPN_NO
     , TARGET_GB_CD
     , TARGET_VALUE
     , REG_NO
     , UDT_NO
) VALUES

	(
       #{cpnNo}
     , #{item.targetGbCd}
     , #{item.targetValue}
     , #{regNo}
     , #{udtNo}
	)

mapper.select:
/* CouponMapper.getExistingGoodsTargetRows: 유효한 상품 대상 목록 조회 */ SELECT GB.GOODS_ID AS TARGET_VALUE , GB.GOODS_ID , GB.GOODS_NM , GB.ERP_STYLE_CD , CONCAT('[', GB.GOODS_ID, '] ', IFNULL(GB.GOODS_NM, '')) AS TARGET_NM FROM GOODS_BASE GB WHERE GB.GOODS_ID IN
#{item}
ORDER BY GB.GOODS_ID ASC

/* CouponMapper.getExistingExhibitionTargetRows: 유효한 기획전 대상 목록 조회 */ SELECT CAST(EB.EXHIBITION_NO AS CHAR) AS TARGET_VALUE , EB.EXHIBITION_NO , EB.EXHIBITION_NM , CONCAT('[', EB.EXHIBITION_NO, '] ', IFNULL(EB.EXHIBITION_NM, '')) AS TARGET_NM FROM EXHIBITION_BASE EB WHERE EB.EXHIBITION_NO IN
#{item}
AND IFNULL(EB.DEL_YN, 'N') = 'N' ORDER BY EB.EXHIBITION_NO ASC

/* CouponMapper.getExistingCategoryTargetRows: 유효한 카테고리 대상 목록 조회 */ SELECT C.CATEGORY_ID AS TARGET_VALUE , C.CATEGORY_ID , C.CATEGORY_NM , C.CATEGORY_LEVEL , CONCAT('[', C.CATEGORY_ID, '] ', IFNULL(C.CATEGORY_NM, '')) AS TARGET_NM FROM CATEGORY C WHERE C.CATEGORY_ID IN
#{item}
ORDER BY C.CATEGORY_ID ASC
